using System.Collections.Generic;\nusing UnityEngine;\n\npublic class AIManager : MonoBehaviour\n{\n    private List<string> conversationMemory;\n    private string currentModel;\n    private const string QWEN_MODEL = "Qwen";\n    private const string PHI_3_MODEL = "Phi-3";\n\n    void Start()\n    {\n        conversationMemory = new List<string>();\n        currentModel = QWEN_MODEL; // Initialize with the default model\n    }\n\n    public void SwitchModel(string model)\n    {\n        if (model == QWEN_MODEL || model == PHI_3_MODEL)\n        {\n            currentModel = model;\n            Debug.Log("Switched to model: " + currentModel);\n        }\n        else\n        {\n            Debug.LogError("Invalid model specified: " + model);\n        }\n    }\n\n    public void ProcessPrompt(string userPrompt)\n    {\n        conversationMemory.Add(userPrompt);\n        // Add your logic here to process the prompt using the current model\n        Debug.Log("Processing prompt: " + userPrompt + " with model: " + currentModel);\n    }\n\n    public void RetrieveConversationMemory()\n    {\n        foreach (var memory in conversationMemory)\n        {\n            Debug.Log(memory);\n        }\n    }\n}